var recipesByIngredient = make(map[string]map[RecipeType]*CookingRecipe)

func init() {
	for i := range CookingRecipes {
		r := &CookingRecipes[i]
		if recipesByIngredient[r.Ingredient] == nil {
			recipesByIngredient[r.Ingredient] = make(map[RecipeType]*CookingRecipe)
		}
		recipesByIngredient[r.Ingredient][r.Type] = r
	}
}

func GetRecipe(ingredient string, recipeType RecipeType) *CookingRecipe {
	if m, ok := recipesByIngredient[ingredient]; ok {
		return m[recipeType]
	}
	return nil
}

func GetSmeltingRecipe(ingredient string) *CookingRecipe {
	return GetRecipe(ingredient, Smelting)
}

func GetBlastingRecipe(ingredient string) *CookingRecipe {
	return GetRecipe(ingredient, Blasting)
}

func GetSmokingRecipe(ingredient string) *CookingRecipe {
	return GetRecipe(ingredient, Smoking)
}

func GetCampfireRecipe(ingredient string) *CookingRecipe {
	return GetRecipe(ingredient, CampfireCooking)
}
